insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hokkaido' and m.slug = 'sapporo'), 'hokkaido-sapporo-emergency-alert', '高齢者あんしんコール事業（札幌市）', '札幌市が実施する高齢者向けの緊急通報システム事業です。自宅にボタン式の通報機器等を設置し、急病や事故などの緊急時に24時間体制の受信センターへ通報できるほか、月1回程度の「お元気コール」による定期的な安否確認・声かけも行われます。対象となる可能性がある方は、一人暮らし高齢者や高齢者のみ世帯などで、詳細要件は公式でご確認ください。', NULL, 'service', '札幌市内在宅で、(1)65歳以上のひとり暮らし、または世帯員全員が65歳以上の世帯に属し、慢性疾患がある・要支援または要介護認定を受けている・介護予防/日常生活支援総合事業の事業対象者のいずれかに該当する方、(2)60歳以上65歳未満のひとり暮らしで要支援または要介護認定を受けている方、(3)85歳以上のひとり暮らし高齢者（身体状況を問わない）のいずれかに対象となる可能性があります。老人ホームやサービス付き高齢者向け住宅等の入居者は対象外とされています。詳細な要件は公式サイトでご確認ください。', '利用料金は月額900円です。市町村民税非課税世帯は月額300円、生活保護受給世帯は無料とされています（公式ページに記載）。詳細・最新の料金は公式サイトでご確認ください。', '随時受付。詳細は公式サイトまたはお住まいの区保健福祉課でご確認ください。', 'お住まいの区役所保健福祉課窓口、または札幌市の電子申請フォーム（Grafferスマート申請）から申請できます。新規申請のほか、内容変更・廃止の申請様式もあります。詳細・最新の申請方法は公式サイトでご確認ください。', '申請書類の詳細は公式ページに明記が確認できませんでした。区保健福祉課の窓口でご確認ください。', NULL, '札幌市 各区役所保健福祉課（高齢者担当）', '', 'https://www.city.sapporo.jp/koreifukushi/denshishinsei/anshincall.html', 'https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html', '介護保険サービス以外に札幌市が行っている高齢者支援（地域支援事業など）／札幌市', '2026-07-01', 'high', ARRAY['requiredDocumentsText', 'contactPhone（区ごとに異なるため代表電話は明記せず、電子申請ページのリンクを案内）']::text[], '本情報は公式サイトの記載に基づく概括です。対象者要件・申請方法の詳細は変更される場合があるため、必ず最新の公式情報またはお住まいの区役所保健福祉課でご確認ください。当サイトは申請の可否を保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
