insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'miyagi' and m.slug = 'sendai'), 'miyagi-sendai-emergency-alert', '緊急通報システム機器の貸し出し（仙台市）', '仙台市が、ひとり暮らし高齢者等の自宅に緊急通報用の機器を貸与し、急病や事故など緊急時にボタン一つで市委託の警備会社につながり、安否確認や駆けつけ対応を行う可能性がある事業です。詳細な対象要件・費用は公式サイトでご確認ください。', NULL, 'service', '仙台市内に在住し、65歳以上で日常生活上注意を要するひとり暮らしの方、または重度要介護者と同居し実質的にひとり暮らし状態にある65歳以上の方などが対象となる可能性があります（社会福祉施設等への3ヶ月以上の入所者は原則対象外とされる場合があります）。詳細な要件は公式で確認が必要です。', '機器の貸与・設置費用は無料とされていますが、月額の利用料（例：550円程度）が発生する場合や、介護保険料の段階に応じて無料となる場合があるなど、費用体系は条件により異なる可能性があります。詳細は公式で確認してください。', '随時申請可能とみられますが、機器の仕様変更等に伴い申請条件が変更される場合があるため、最新情報を公式サイトでご確認ください。', 'お住まいの区役所・総合支所の高齢担当窓口、または地域包括支援センターに相談・申請します。申請前に、市が委託する警備会社による訪問調査が行われる場合があります。', '緊急通報システム端末利用申請書、利用確約書、（借家の場合）架設承諾書など。詳細・様式は公式サイトの申請書ダウンロードページで確認してください。', FALSE, '仙台市健康福祉局高齢企画課', '022-214-8168', 'https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/hitorigurashi/tsuho.html', 'https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/hitorigurashi/tsuho.html', '緊急通報システム機器の貸し出し｜仙台市', '2026-07-01', 'high', ARRAY['targetPeople（年齢・要介護状態等の詳細要件の網羅性）', 'benefitAmountText（月額利用料の金額・免除条件の詳細）', 'requiredDocumentsText（最新の様式・必要書類の網羅性）']::text[], '本ページは公的支援制度の概要を紹介するものであり、受給を確約するものではありません。対象要件・費用・申込方法の詳細は必ず仙台市公式サイトまたは担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
