insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"miyagi-sendai-emergency-alert","status":"published","title":"緊急通報システム機器の貸し出し（仙台市）","officialUrl":"https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/hitorigurashi/tsuho.html","topic":"emergency-alert"}'::jsonb, 'pilot:miyagi-sendai-emergency-alert:bWl5YWdpLXNlbmRhaS1lbWVyZ2VuY3ktYWxlcnR8' from public.support_programs sp where sp.slug='miyagi-sendai-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'saitama' and m.slug = 'saitama'), 'saitama-saitama-emergency-alert', 'ひとり暮らし高齢者等あんしんコールセンター相談事業（緊急通報機器の設置）', 'さいたま市が、ひとり暮らしの高齢者等の自宅に緊急通報機器を設置し、急病や事故の際に24時間体制で通報・相談に対応する市独自の見守り支援事業です。希望者には定期的な電話による安否確認も行われる可能性があります。', NULL, 'service', 'さいたま市内に居住する65歳以上のひとり暮らし高齢者で、慢性疾患などにより日常生活において常時注意を要する方が対象となる可能性があります。具体的な要件（所得・同居家族の有無等）は公式情報でご確認ください。', '緊急通報機器の設置費・維持管理費は市が負担するとされています。ただし利用者の都合による機器移設等の再設置費や、破損・紛失時の実費は利用者負担となる場合があります。固定電話がない世帯には福祉電話事業による回線貸与（基本料は利用者負担の可能性）が案内されています。', '随時受付の可能性がありますが、詳細は公式情報でご確認ください。', '各区役所の高齢介護課の窓口で申請するか、さいたま市の電子申請・届出サービスから手続きできる可能性があります。詳細は公式ページまたは担当窓口でご確認ください。', '申請書等が必要になる可能性があります。具体的な必要書類は各区役所高齢介護課にご確認ください。', TRUE, 'さいたま市 福祉局長寿応援部高齢福祉課在宅事業係', '048-829-1260', 'https://www.city.saitama.lg.jp/002/003/003/002/005/kinkyuutuuhou.html', 'https://www.city.saitama.lg.jp/002/003/003/002/005/kinkyuutuuhou.html', 'さいたま市／あんしんコールセンター相談事業（緊急通報機器の設置）', '2026-07-01', 'high', ARRAY['所得要件・同居家族要件の有無', '機器の具体的な種類（本体・ペンダント型発信機以外の有無）', '利用料金の詳細（無料か一部自己負担か）', '申請時の必要書類の具体的内容', '電子申請・届出サービスの対応状況']::text[], '本情報は公式サイトの記載に基づく概括であり、対象要件・料金・手続きの詳細は変更される場合があります。申請前に必ずさいたま市公式サイトまたは担当窓口で最新情報をご確認ください。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
