insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'chiba' and m.slug = 'chiba'), 'chiba-chiba-emergency-alert', '高齢者緊急通報システム事業（千葉市）', '千葉市が実施する、ひとり暮らし高齢者等を対象とした緊急通報システム事業です。自宅に緊急通報機器（本体・ペンダント型発信器）や安否確認センサー、火災センサーなどを設置し、急病や事故の際にガードマンが駆けつけ、必要に応じて警察・消防へ通報する仕組みです。現行制度は見直しが予定されており、対象となるかどうかや詳しい要件、最新の受付状況は公式ページ・窓口でご確認ください。', NULL, 'service', '在宅でおおむね65歳以上のひとり暮らし高齢者等が対象です。協力員を最低1名登録できることが要件とされており、同居者が重度要介護者であるケースなども対象となる可能性があります。詳細な要件は公式で確認してください。', 'システム利用料・設置料は無料とされていますが、電話料金（目安約40〜50円/月）は利用者負担となり、通信試験時に目安約200円程度の費用が必要とされる場合があります。金額は変更の可能性があるため公式で確認してください。', '公式ページによれば、現行の本事業は令和8年10月30日（金）をもって新規受付を終了し、令和9年1月開始予定の新制度へ移行するとされています。申請を検討する場合は、最新の受付状況を公式ページまたは窓口で必ずご確認ください。', 'お住まいの区の保健福祉センター高齢障害支援課の窓口に、利用申請書等の必要書類を提出して申請する方法が案内されています。オンライン申請の可否は公式ページで確認できませんでした。', '利用申請書、協力員・親族連絡先登録同意書、誓約書、電話回線承諾書兼確認票のほか、高齢者福祉電話貸与を希望する場合は貸与契約書などが必要とされる場合があります。詳細は窓口でご確認ください。', FALSE, '千葉市保健福祉局高齢障害部高齢福祉課', '043-245-5250', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/kinkyuutuuhou.html', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/kinkyuutuuhou.html', '千葉市：高齢者緊急通報システムのご案内', '2026-07-01', 'high', ARRAY['新制度（令和9年1月開始予定）の具体的な内容・対象要件・利用料', '対象年齢・世帯要件の詳細な運用（協力員登録できない場合の代替措置など）', '利用料・通信試験費用の正確な金額の最新値', 'オンライン申請の可否', '必要書類の全リスト']::text[], '本ページは制度の概要をまとめたものであり、対象となるかどうかや受給の可否を保証するものではありません。現行制度は見直しが予定されているため、最新の条件・費用・受付状況・新制度の詳細は必ず千葉市公式サイトまたは窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
