insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"chiba-chiba-emergency-alert","status":"published","title":"高齢者緊急通報システム事業（千葉市）","officialUrl":"https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/kinkyuutuuhou.html","topic":"emergency-alert"}'::jsonb, 'pilot:chiba-chiba-emergency-alert:Y2hpYmEtY2hpYmEtZW1lcmdlbmN5LWFsZXJ0fOmr' from public.support_programs sp where sp.slug='chiba-chiba-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'kawasaki'), 'kanagawa-kawasaki-emergency-alert', '高齢者等緊急通報システム（川崎市）', '川崎市が実施する、ひとり暮らし高齢者等を対象とした緊急通報システムです。急病・事故などの緊急時に通報でき、24時間365日の対応体制や健康相談などのサービスが受けられる可能性があります。携帯型（GPS機能付き）と自宅設置型（緊急ペンダント、火災・ガス・生活リズムセンサー等）の2種類があるとされ、詳細は公式サイトでご確認ください。', NULL, 'service', '公式サイトによれば、原則65歳以上で慢性疾患等により日常生活上注意を要するひとり暮らし高齢者、または同居人が日中不在の高齢者等が対象となる可能性があります。75歳以上のひとり暮らしは要件が緩和され、基本サービスを利用できる場合があるとのことです。認知症等により行方不明となるおそれがある高齢者向けのメニューもあるとされています。携帯型と自宅設置型で対象要件が一部異なり、併用はできないとされています。なお、65歳未満の重度身体障害者等を対象とした類似の別事業（緊急通報システム設置運営事業）が障害福祉課所管で別途存在する可能性があり、該当する場合は自治体窓口でご確認ください。正確な対象要件は公式サイト・自治体窓口でご確認ください。', '月額利用料は所得等に応じて段階的に設定されており、無料から一定額（公式サイトによれば上限4,580円程度とされる場合あり）まで幅があるとされています。正確な料金区分は公式サイトでご確認ください。', '随時受付とされていますが、詳細は自治体窓口でご確認ください。', '地域包括支援センター、各区役所高齢・障害課の窓口での申請のほか、オンライン手続（e-KAWASAKI）でも申請できる場合があるとされています。詳細は公式サイトまたは窓口でご確認ください。', '申請書等の様式が公式サイトに掲載されている場合があります。所得状況を確認できる書類等が必要となる可能性があります。詳細は窓口でご確認ください。', TRUE, '川崎市健康福祉局長寿社会部高齢者在宅サービス課', '044-200-2911', 'https://www.city.kawasaki.jp/350/page/0000022594.html', 'https://www.city.kawasaki.jp/350/page/0000022594.html', '川崎市：高齢者等緊急通報システム', '2026-07-01', 'medium', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText', '携帯型と自宅設置型で対象要件・料金体系が異なる可能性がある点', '重度身体障害者向け別事業との対象区分の詳細']::text[], '本情報は公式サイトの記載を要約したものであり、対象要件・利用料・機種の詳細は変更される場合があります。必ず自治体窓口・公式サイトで最新情報をご確認ください。また、65歳未満の重度身体障害者を対象とした類似の別事業が存在する可能性があるため、該当する場合は障害福祉課へお問い合わせください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
