insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"kanagawa-kawasaki-emergency-alert","status":"published","title":"高齢者等緊急通報システム（川崎市）","officialUrl":"https://www.city.kawasaki.jp/350/page/0000022594.html","topic":"emergency-alert"}'::jsonb, 'pilot:kanagawa-kawasaki-emergency-alert:a2FuYWdhd2Eta2F3YXNha2ktZW1lcmdlbmN5LWFs' from public.support_programs sp where sp.slug='kanagawa-kawasaki-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'sagamihara'), 'kanagawa-sagamihara-emergency-alert', '相模原市緊急通報サービス', '相模原市が、ひとり暮らし高齢者や重度身体障害者等の世帯を対象に、急病時に押しボタンで119番通報できる緊急通報装置を自宅に設置する事業です。事前に登録した家族や協力員等の連絡先を活用し、迅速な対応につなげます。', NULL, 'service', '公式情報によると、市内在住・在宅で、65歳以上のひとり暮らし高齢者及び高齢者のみの世帯、常時注意が必要な65歳以上の高齢者または重度身体障害者がいる世帯、ひとり暮らし重度身体障害者及び重度身体障害者のみの世帯が対象となる可能性があります。詳細な要件は公式窓口でご確認ください。', '機器の設置工事費は原則市負担とされていますが、工事内容により自己負担が生じる場合があります。利用料（通信費）は電話回線の種類により異なり、NTTアナログ電話・ひかり電話は月額約400円、その他の電話（ケーブル・IP・ADSL・ISDN等）は月額約1,600円とされています（公式情報時点、変更の可能性あり）。', '随時受付（公式ページに明記された申請期限の記載は確認できませんでした）。', '利用を希望する場合は、訪問調査が必要とされています。高齢者の方は各地区の地域包括支援センター、障害者の方は対象地区の相談窓口へご連絡のうえ、案内に従って申請してください。', '訪問調査を通じて必要書類等が案内される可能性があります。詳細は地域包括支援センターまたは相談窓口・高齢・障害者支援課にご確認ください。', FALSE, '相模原市 高齢・障害者支援課（高齢支援班）', '042-769-9249', 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006378.html', 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006378.html', '緊急通報サービス｜相模原市', '2026-07-01', 'high', ARRAY['targetPeople（年齢・世帯要件の細部、区ごとの窓口対応の差異）', 'benefitAmountText（利用料・自己負担額の詳細、機種による違い）', 'applicationDeadlineText（明示的な期限記載なし、常時受付と推定）', 'requiredDocumentsText（訪問調査後に案内される詳細書類は未確認）']::text[], '本情報は公式ページの内容を要約したものです。対象要件・利用料・自己負担の有無等は変更される場合があるため、申請前に必ず相模原市高齢・障害者支援課または地域包括支援センターに直接ご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
