insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"kanagawa-sagamihara-emergency-alert","status":"published","title":"相模原市緊急通報サービス","officialUrl":"https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006378.html","topic":"emergency-alert"}'::jsonb, 'pilot:kanagawa-sagamihara-emergency-alert:a2FuYWdhd2Etc2FnYW1paGFyYS1lbWVyZ2VuY3kt' from public.support_programs sp where sp.slug='kanagawa-sagamihara-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'niigata' and m.slug = 'niigata'), 'niigata-niigata-emergency-alert', '高齢者あんしん連絡システム（緊急通報装置の貸与）', '新潟市が実施する高齢者向けの緊急通報・見守り事業です。在宅で生活する高齢者等の自宅に、24時間体制の受信センターへ通報できる装置を貸与し、急病や事故等の際の通報対応のほか、安否センサーによる日々の安否確認、電話による定期的な安否確認、健康相談等を行うとされています（公式サイトで確認）。対象となる可能性がある世帯・要件は公式サイトで必ずご確認ください。', NULL, 'service', '公式サイトの記載によれば、(1)65歳以上の方のみで構成される世帯、または65歳以上の方と重度の障がいのある方で構成される世帯であり、かつ(2)要介護状態にある、または医師の治療を要する慢性疾患等があり、日常生活上注意を要し定期的な安否確認等を要する方が対象となる可能性があります。独居（ひとり暮らし）であることが必須要件かどうかは公式ページの記載に幅があるため、詳細は区役所窓口でのご確認をお願いします。', '利用料は世帯の住民税課税状況に応じた月額負担制とされています（公式サイトの記載）：生活保護世帯・世帯全員非課税は0円、住民税均等割課税世帯は550円、住民税所得割課税世帯は1,100円、とされています。機器の設置費用等の有無は公式サイトでご確認ください。', '随時申請可能とされていますが、詳細は区役所窓口でご確認ください。', 'お住まいの区の区役所健康福祉課高齢介護担当、地域保健福祉センター、または地域包括支援センターで申請するとされています（公式サイトの記載）。', '公式サイトによれば、高齢者福祉サービス申請書、調査票1・2、利用確約書、協力員同意書などが必要とされています。詳細・様式は区役所窓口でご確認ください。', FALSE, NULL, NULL, 'https://www.city.niigata.lg.jp/iryo/korei/anshinseikatsu/anshinrenraku.html', 'https://www.city.niigata.lg.jp/iryo/korei/anshinseikatsu/anshinrenraku.html', 'あんしん連絡システム（新潟市公式サイト）', '2026-07-01', 'medium', ARRAY['独居（ひとり暮らし）が必須条件かページ冒頭の説明と対象要件記載の間に表現の幅があり、正確な適用条件は区役所での確認が必要', '重度障がい者世帯の場合の障がいの程度・等級の具体的基準は公式ページに明記が薄く要確認', '機器の設置費用・初期費用の有無や貸与機器の具体的種類（ペンダント型・センサー種別等）の詳細は公式ページの追加確認が望ましい', '事業の根拠となる実施要綱の正式名称・最新版は未確認']::text[], '本情報は公式サイトの記載に基づく概括であり、対象要件・利用料・申請手続きの詳細は変更される場合があります。申請の可否や条件は必ず新潟市（お住まいの区の区役所健康福祉課高齢介護担当）にご確認ください。当サイトは制度情報の案内のみを行うものであり、申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
