insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'shizuoka'), 'shizuoka-shizuoka-emergency-alert', 'ひとり暮らし高齢者等緊急通報システムの貸し出し', '静岡市が、ひとり暮らしの高齢者等の自宅に緊急通報用の機器（本体・ペンダント型）や火災報知器・ガス漏れ警報器を貸与し、急病や火災などの緊急時に委託事業者の受信センターへ通報できるようにする事業です。対象要件や費用の詳細は公式サイトでご確認ください。', NULL, 'service', '65歳以上のひとり暮らし高齢者（高齢者のみの世帯で一方が寝たきり状態等の場合を含む可能性）で、生活保護世帯または世帯全員が市民税非課税の世帯に属し、固定電話を利用しており、緊急連絡先を2件程度知らせられる方が対象となる可能性があります。詳細な要件は公式サイトでご確認ください。', '機器の設置・撤去費用および月々の利用料は無料とされていますが、毎日の機能確認通話にかかる電話代（1日あたり10円程度とされる）や、移転・故障・破損時の修理費用等は自己負担となる場合があるとされています。詳細は公式サイトでご確認ください。', '随時受付の可能性があります。詳細は公式サイトまたは担当窓口でご確認ください。', '窓口（各区高齢介護課）での申請、または電子申請フォームからの申込みが可能とされています（要本人確認書類等）。詳細な必要書類・手続きは公式サイトまたは担当窓口でご確認ください。', '本人確認書類や申請書類等が必要とされています。詳細は公式サイトまたは担当窓口でご確認ください。', TRUE, '静岡市保健福祉長寿局健康福祉部高齢者福祉課高齢者支援係', '054-221-1201', 'https://www.city.shizuoka.lg.jp/s2837/s002727.html', 'https://www.city.shizuoka.lg.jp/s2837/s002727.html', 'ひとり暮らし高齢者等緊急通報システムの貸し出し（静岡市公式ホームページ）', '2026-07-01', 'high', ARRAY['targetPeople（二人暮らしの要件詳細、障害者の対象可否）', 'applicationDeadlineText（随時受付か時期指定か）', 'requiredDocumentsText（具体的書類名）', 'benefitAmountText（自己負担額の詳細条件）']::text[], '本情報は静岡市公式サイトの記載に基づく概要です。対象要件・費用・手続きの詳細、最新情報は必ず公式サイトまたは担当窓口でご確認ください。申請すれば必ず利用できることを保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
