insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"shizuoka-shizuoka-emergency-alert","status":"published","title":"ひとり暮らし高齢者等緊急通報システムの貸し出し","officialUrl":"https://www.city.shizuoka.lg.jp/s2837/s002727.html","topic":"emergency-alert"}'::jsonb, 'pilot:shizuoka-shizuoka-emergency-alert:c2hpenVva2Etc2hpenVva2EtZW1lcmdlbmN5LWFs' from public.support_programs sp where sp.slug='shizuoka-shizuoka-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'hamamatsu'), 'shizuoka-hamamatsu-emergency-alert', '緊急通報システムの貸与（浜松市）', '浜松市が、心疾患・脳血管障害などのあるひとり暮らし高齢者や75歳以上の高齢者世帯などを対象に、急病・事故時に通報できる緊急通報システム（装置）を貸与する制度です。利用料は世帯の市民税課税状況により異なります。詳しい対象要件・料金・申込方法は公式サイトまたは高齢者相談センター（地域包括支援センター）でご確認ください。', NULL, 'service', '公式サイトの案内によれば、65歳以上で心疾患・脳血管障害など循環器系疾患のあるひとり暮らし高齢者（昼夜いずれか高齢者のみの世帯を含む）、75歳以上のひとり暮らし高齢者、75歳以上で支援が必要な高齢者世帯などが対象となる可能性があります。詳細な要件は自治体窓口で確認が必要です。', '緊急通報システム（装置）の貸与。利用料は市民税非課税世帯は無料、市民税課税世帯は月額1,100円とされています（公式サイトの案内による）。別途、通話料と週1回の通信テストにかかる費用は利用者負担となる場合があります。金額・条件は変更される可能性があるため、必ず公式サイトまたは窓口でご確認ください。', '随時受付と考えられますが、公式サイトに明記はありません。詳細は窓口でご確認ください。', '公式サイトの案内では具体的な申込窓口の手続きが明記されておらず、高齢者相談センター（地域包括支援センター）、各福祉事業所担当窓口、または浜松市役所健康福祉部高齢者福祉課への相談・確認が案内されています。詳細は「生活支援事業実施要綱」等を参照するよう案内されているため、申込方法の詳細は窓口でご確認ください。', '公式サイトに具体的な必要書類の記載はありませんでした。市民税課税状況により利用料が異なるため、税に関する確認が必要になる可能性があります。詳細は窓口でご確認ください。', FALSE, '浜松市役所 健康福祉部 高齢者福祉課', '053-457-2789', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/kinkyuu.html', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/kinkyuu.html', '緊急通報システムの貸与／浜松市', '2026-07-01', 'medium', ARRAY['targetPeople', 'applicationMethodText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は公式サイトの記載に基づく概括であり、対象要件・利用料・申込方法などの詳細は変更される場合があります。必ず浜松市公式サイトまたは窓口で最新情報をご確認ください。申請すれば必ず利用できることを保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
