insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"shizuoka-hamamatsu-emergency-alert","status":"published","title":"緊急通報システムの貸与（浜松市）","officialUrl":"https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/kinkyuu.html","topic":"emergency-alert"}'::jsonb, 'pilot:shizuoka-hamamatsu-emergency-alert:c2hpenVva2EtaGFtYW1hdHN1LWVtZXJnZW5jeS1h' from public.support_programs sp where sp.slug='shizuoka-hamamatsu-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'aichi' and m.slug = 'nagoya'), 'aichi-nagoya-emergency-alert', 'ひとり暮らし高齢者緊急通報事業（あんしん電話）', '名古屋市では、ひとり暮らしの高齢者等を対象に、緊急時に「緊急」ボタンを押すことで消防局防災指令センターまたは民間コールセンターへ通報できる緊急通報装置（据置型・携帯型）を貸与しています。24時間365日の相談対応や定期的な安否確認電話も行われます。詳しい対象条件や利用料は名古屋市公式サイトでご確認ください。', NULL, 'service', '65歳以上で高血圧や心臓病などの慢性疾患がありひとり暮らしの方、75歳以上のみで構成される世帯で他の世帯員が寝たきり状態にある方、同居人が就労等で長時間不在となり実質的にひとり暮らし状態にある方など、対象となる可能性があります（詳細は公式で確認）。', '緊急通報装置の貸与および24時間365日の看護師相談、年4回程度の安否確認電話などのサービスが提供されるとされています。前年の所得が1,695,000円以上の場合、月額2,145円程度の自己負担が生じる場合があるとされています（詳細は公式で確認）。', '', 'お住まいの区の区役所福祉課高齢福祉担当（支所の場合は区民福祉課）で申請できるほか、電子申請サービスも利用可能とされています（詳細は公式で確認）。', '', TRUE, '名古屋市健康福祉局高齢福祉部高齢福祉課在宅福祉担当', '052-972-2544', 'https://www.city.nagoya.jp/kenkofukushi/koureisha/1016427/1016428.html', 'https://www.city.nagoya.jp/kenkofukushi/koureisha/1016427/1016428.html', '名古屋市:ひとり暮らしの高齢者などの支援（暮らしの情報）', '2026-07-01', 'high', ARRAY['targetPeople（世帯構成や慢性疾患の具体的な認定基準の詳細）', 'benefitAmountText（自己負担額の所得判定基準や機器種別ごとの差異）', 'onlineApplicationAvailable（電子申請の対応範囲の詳細）', '区ごとの窓口対応の違い']::text[], '本情報は名古屋市公式サイトの内容に基づく概括です。対象要件・利用料・機器の種類などは変更される場合があるため、申請前に必ず公式サイトまたはお住まいの区の窓口でご確認ください。申請すれば必ず利用できるとは限りません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
