insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"aichi-nagoya-emergency-alert","status":"published","title":"ひとり暮らし高齢者緊急通報事業（あんしん電話）","officialUrl":"https://www.city.nagoya.jp/kenkofukushi/koureisha/1016427/1016428.html","topic":"emergency-alert"}'::jsonb, 'pilot:aichi-nagoya-emergency-alert:YWljaGktbmFnb3lhLWVtZXJnZW5jeS1hbGVydHzj' from public.support_programs sp where sp.slug='aichi-nagoya-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kyoto' and m.slug = 'kyoto'), 'kyoto-kyoto-emergency-alert', '緊急通報システム「あんしんネット119」（京都市）', 'ひとり暮らしの高齢者や重度身体障がいのある方等を対象に、急病や災害などの緊急時にペンダント型または専用機の緊急ボタンひとつで京都市消防局指令センターへ通報できる緊急通報装置を貸与する、京都市消防局・保健福祉局の事業です。相談ボタンによる24時間の保健・健康相談も利用できます。', NULL, 'service', '京都市内に住所があり、次のいずれかに該当する方が対象です。(1)おおむね65歳以上のひとり暮らしの高齢者や高齢者のみで構成する世帯等で、心身病弱等のため緊急時に自分で対処することが困難な方。(2)ひとり暮らしの身体障害者手帳1・2級の重度身体障害者や重度身体障害者のみで構成する世帯等で、緊急時に自分で対処することが困難な方。(3)その他、上記(1)(2)と同程度の状態にあると市長が認めたおおむね65歳以上の高齢者または重度身体障害者の方。近隣協力員2名以上を申請者側で確保することが原則の条件です。', '緊急通報装置一式の貸与。機器の利用料（月額）は世帯の生計中心者の前年合計所得金額により区分：生活保護法または中国残留邦人等支援法の支援給付受給世帯は0円、生計中心者の合計所得35万円以下は150円、35万円超40万円以下は768円、40万円超は1,462円。支払いは口座引き落としのみで口座登録が必要です。このほか電話の基本料（月額1,900円程度）と通話料は利用者負担、機器は貸与のため利用終了時は返還、紛失時は機器本体料金の負担が必要です。', '随時受付（受付終了の案内なし。最新状況は公式または窓口で確認してください）。', 'お住まいの区役所・支所の健康福祉部担当課（または京北出張所）に備え付けの申請書に、利用登録票・承諾書を添えて申請してください。担当者が後日訪問等を行った上で、利用の適否を知らせます。', '区役所・支所備え付けの申請書、利用登録票、承諾書。詳細は申請窓口で確認してください。', FALSE, '京都市消防局 予防部 予防課', '075-212-6695', 'https://www.city.kyoto.lg.jp/shobo/page/0000076672.html', 'https://www.city.kyoto.lg.jp/shobo/page/0000076672.html', '京都市消防局：緊急通報システム「あんしんネット119」', '2026-07-01', 'high', '{}'::text[], '本情報は京都市公式ページおよび公式リーフレットに基づく要約です。介護サービス希望の相談・家族への伝達手段目的の利用・防犯目的の利用は対象外とされています。近隣協力員の確保状況や個々の所得区分など、実際の利用可否は担当課の訪問調査等を経て決定されるため、申請すれば必ず利用できるとは限りません。詳細・最新情報は必ず公式または窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
