insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'sakai'), 'osaka-sakai-emergency-alert', '堺市 高齢者緊急通報システム事業', '堺市が、ひとり暮らし高齢者や高齢者のみの世帯などを対象に、急病や事故などの緊急時に消防局や受信センターへ通報できる緊急通報装置を貸与する事業です。所得区分に応じて利用料が異なります。', NULL, 'service', '堺市内に住所を有し、病弱等でひとり暮らしの高齢者、または高齢者のみの世帯に属する方で、システムの利用が必要と認められる方が対象となる可能性があります。家族の就労・通学等により昼間または夜間に独居となる高齢者も対象に含まれる場合があるとされています。具体的な年齢基準や介護度・健康状態の認定基準は公式ページに明記がなく、区役所地域福祉課での確認が必要です。', '生活保護世帯・所得税非課税世帯は無料、それ以外の課税世帯は8,400円です。昼間または夜間に独居となる場合は機器代が別途実費で必要となる場合があります。金額の詳細や改定の有無は公式サイトでご確認ください。', '', '申込みに必要な書類を、居住する区の区役所地域福祉課へ提出する方法とされています。緊急通報受信時に利用者の状況確認等を行う協力員2名の登録が必要です。詳細な手続きは必ず公式サイトまたは区役所窓口でご確認ください。', '申請書等、区役所地域福祉課が案内する書類一式が必要とされています。詳細は公式サイトまたは窓口でご確認ください。', FALSE, '堺市 健康福祉局 長寿支援課（または各区役所地域福祉課）', '072-228-8347', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kinkyutsuho.html', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kinkyutsuho.html', '高齢者緊急通報システム事業 - 堺市', '2026-07-01', 'high', ARRAY['targetPeople（具体的な年齢基準がページ本文に明記なし。「おおむね65歳以上」は一次調査の推測であり公式ページでは確認できなかった）', 'targetPeople（要介護度・健康状態等の詳細な認定基準）', 'benefitAmountText（機器代の具体的な金額・年度改定の有無）', 'requiredDocumentsText（申請書類の具体的な一覧）', '協力員（緊急連絡先）登録要件の詳細', '身体障害者が本事業の対象に含まれるか（別事業「身体障害者緊急通報システム事業」の存在を示唆する情報があるが、本ページには明記なし）']::text[], '本情報は堺市公式サイトの案内に基づく概括であり、対象者の詳細要件・利用料金・機器の種類等は変更される場合があります。申請可否や最終的な決定は堺市の審査によります。当サイトは申請の保証や代行を行うものではありません。最新情報は必ず堺市公式サイトまたは区役所窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
