insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hyogo' and m.slug = 'kobe'), 'hyogo-kobe-emergency-alert', '緊急通報システム ケアライン119（神戸市）', '神戸市が消防局を通じて実施する緊急通報の仕組みです。ひとり暮らしの高齢者や重度の身体障害者、持病のある方などを対象に、固定電話を使った緊急通報と近隣協力者・消防署による迅速な対応を組み合わせた制度です。詳しい対象条件・利用料金・手続きは公式サイトでの確認が必要です。', NULL, 'service', '神戸市内に居住し、(1)ひとり暮らしで持病があり急病等のリスクがある方、(2)重度の身体障害があり緊急時の対応が困難な方、(3)おおむね65歳以上で病弱なひとり暮らしの方のいずれかに該当する方、またはこれらに該当する方と同居し、昼間ひとりで過ごす時間が長い方（同居する配偶者等）が対象となる可能性があります。固定電話（IP電話可、携帯電話不可）を所有し、緊急時におおむね5分程度で駆けつけ可能な近隣協力者を確保できることが要件とされています。詳細な対象条件は公式サイトでの確認が必要です。', '公式ページには利用料金・費用負担についての具体的な記載が確認できませんでした。無料か有料かは公式サイトまたは問い合わせでの確認が必要です。', '随時申込み可能（年間を通じて受付、期限の記載なし）。', '申込用紙に必要事項を記入し、近隣協力者の記名・民生委員の確認を得たうえで、最寄りの消防署へ提出する方法と、e-KOBE（電子申請システム）を利用したオンライン申請の方法があります。申込用紙は消防署・区役所で入手可能です。', '申込用紙（近隣協力者の記名、民生委員の確認・記名が必要）。詳細な添付書類は公式サイトまたは消防署への確認が必要です。', TRUE, '神戸市消防局予防部予防課', '', 'https://www.city.kobe.lg.jp/a10878/bosai/shobo/119/careline.html', 'https://www.city.kobe.lg.jp/a10878/bosai/shobo/119/careline.html', '緊急通報システムケアライン119 - 神戸市', '2026-07-01', 'medium', ARRAY['利用料金・費用負担の有無', '電話機自体の貸与・補助制度はなし（公式ページには短縮登録機能付き電話やコードレス電話が『より適した』機器として案内されているのみで、貸与制度の記載はない）', '問い合わせ先の電話番号', '近隣協力者を確保できない場合の代替措置の有無']::text[], '本制度の対象条件・利用料金・手続きの詳細は変更される場合があります。申請の可否や条件は必ず神戸市消防局または公式サイトでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
