insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'okayama' and m.slug = 'okayama'), 'okayama-okayama-emergency-alert', '岡山市 緊急通報システムの貸与・給付', '岡山市が、ひとり暮らし高齢者や重度身体障害者等の自宅に、ペンダント型ボタンで近隣協力員や消防局へ通報できる緊急通報システムを貸与する在宅福祉サービスです。急病や事故など緊急時の安否確認・見守り支援を目的としています。対象要件や費用負担は世帯状況により異なるため、詳細は岡山市公式サイトでご確認ください。', NULL, 'service', '対象となる可能性がある方の例として、市内に居住し自宅に電話があり近隣協力員（3人程度）を得られる、65歳以上のひとり暮らしの方、60歳以上65歳未満のひとり暮らしで病弱な方、ひとり暮らしの重度身体障害者、高齢者のみ・障害者のみの世帯に属する特定条件の方などが挙げられています。具体的な対象要件は世帯構成や心身の状況により異なるため、必ず公式情報または窓口でご確認ください。', '設置費用および電池交換費用は、生計中心者の課税状況（所得税額）に応じて全部または一部を利用者が負担する仕組みです。生計中心者が住民税非課税の世帯は無料とされています。緊急通報時を含む通話料は利用者負担です。負担額の具体的な区分は世帯の課税状況により異なるため、公式情報でご確認ください。', NULL, '利用を希望する場合は、最寄りの福祉事務所・支所または高齢者福祉課・障害福祉課へ相談のうえ、利用申請書等（岡山市公式サイトでPDF様式を公開）を提出する流れとされています。詳細な手続きは窓口でのご確認をおすすめします。', '利用申請書等（岡山市公式サイトに様式・要綱がPDFで公開されています）。世帯状況・所得等を確認できる書類の提出を求められる場合があります。詳細は窓口でご確認ください。', FALSE, '岡山市保健福祉局高齢福祉部高齢者福祉課', '086-803-1230', 'https://www.city.okayama.jp/kurashi/0000014403.html', 'https://www.city.okayama.jp/kurashi/0000014403.html', '在宅福祉サービス／緊急通報システムの貸与・給付（岡山市）', '2026-07-01', 'high', ARRAY['targetPeople（対象年齢・世帯要件の詳細区分）', 'benefitAmountText（課税区分ごとの具体的な自己負担額）', 'requiredDocumentsText（提出書類の詳細一式）', '対象となる障害者の等級・区分の詳細', 'ページ掲載日が2009年と古く、現行制度内容が変更されている可能性は残る']::text[], '本情報は岡山市公式サイトの内容をもとに概括したものです。対象要件・自己負担額・申請手続きの詳細は世帯状況により異なるため、必ず岡山市高齢者福祉課・障害福祉課または最寄りの福祉事務所に直接ご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
