insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hiroshima' and m.slug = 'hiroshima'), 'hiroshima-hiroshima-emergency-alert', 'あんしん電話設置事業（緊急通報システム）', '広島市が、ひとり暮らし高齢者等の自宅に緊急通報機器を貸与し、急病・事故時にボタン操作で通報・支援につなげる可能性がある事業です。詳細な対象要件・利用料は公式情報でご確認ください。', NULL, 'service', '病弱などで日常生活に注意が必要なおおむね65歳以上のひとり暮らし高齢者、または高齢者のみの世帯で、原則2人の協力員を確保できる方が対象となる可能性があります。詳細は公式情報でご確認ください。', '緊急通報機器（固定電話型または携帯電話型）を貸与。月額利用料は世帯の市民税課税区分等により異なり、課税世帯・非課税世帯・生活保護受給世帯で金額が異なる可能性があります（工事費・保守料込み）。正確な金額は公式情報でご確認ください。', '随時受付の可能性がありますが、公式情報でご確認ください。', '協力員の了承を得た上で、必要書類をお住まいの区の福祉課に提出して申請します。最近転入した方は市民税証明書の添付が必要な場合があります。', '申請書類、市民税証明書（最近転入した方）等が必要となる可能性があります。詳細はお住まいの区福祉課にご確認ください。', FALSE, '広島市高齢福祉課', '082-504-2145', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015440.html', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015440.html', 'あんしん電話設置（高齢者）｜広島市公式ウェブサイト', '2026-07-01', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', '障害者が対象に含まれるかどうか（このページでは高齢者向けとしてのみ記載）']::text[], '本情報は公式サイトの内容を基に作成していますが、対象要件・利用料・手続きは変更される場合があります。申請前に必ず広島市公式サイトまたはお住まいの区福祉課で最新情報をご確認ください。当サイトは制度の情報提供のみを行っており、受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
