insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"hiroshima-hiroshima-emergency-alert","status":"published","title":"あんしん電話設置事業（緊急通報システム）","officialUrl":"https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015440.html","topic":"emergency-alert"}'::jsonb, 'pilot:hiroshima-hiroshima-emergency-alert:aGlyb3NoaW1hLWhpcm9zaGltYS1lbWVyZ2VuY3kt' from public.support_programs sp where sp.slug='hiroshima-hiroshima-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'kitakyushu'), 'fukuoka-kitakyushu-emergency-alert', 'あんしん通報システム（北九州市）', '北九州市が実施する緊急通報システム事業です。ひとり暮らし高齢者等の自宅に緊急通報装置・煙/熱センサー・ペンダント型送信機を貸与・設置し、急病や火災などの際にボタン操作等でコールセンターや消防・救急、警備員派遣につながる仕組みです。24時間の医療・福祉相談にも対応するとされています（公式サイトで要確認）。', NULL, 'service', '公式サイトによれば、おおむね65歳以上の高齢者のみで構成される世帯で健康上注意が必要な方、および緊急事態を自力で回避できないと認められる重度身体障害者（身体障害者手帳1・2級等）のみ、または高齢者との混在世帯が対象となる可能性があります。詳細な年齢・等級要件は公式サイトでの確認が必要です。', '利用料は、市民税非課税世帯・生活保護受給世帯は無料、それ以外の世帯は月額1,705円（消費税込、通話料は利用者負担、2025年9月時点の公式表示）とされています。料金は変更される可能性があるため公式サイトで確認してください。', NULL, '各区役所の高齢者・障害者相談係、または小学校区ごとの地域包括支援センターへ申請します。在宅福祉サービス利用登録申込書、協力員届出書、誓約書等の提出が必要とされています（詳細は公式サイト・窓口で要確認）。', '在宅福祉サービス利用登録申込書、協力員届出書、誓約書、（借家の場合）承諾書、電話回線に関する誓約書など。詳細は申請窓口で確認してください。', FALSE, '北九州市消防局予防課／各区役所高齢者・障害者相談係', '093-582-3836', 'https://www.city.kitakyushu.lg.jp/shoubou/14000050.html', 'https://www.city.kitakyushu.lg.jp/shoubou/14000050.html', 'あんしん通報システム（火災・救急など） - 北九州市', '2026-07-01', 'high', ARRAY['targetPeople（年齢要件・障害等級の詳細）', 'benefitAmountText（利用料金の最新値・改定の可能性）', 'requiredDocumentsText（必要書類の最新一覧）']::text[], '本情報は公式サイトの記載内容を基にした概括です。対象要件・利用料金・提供機器の種類などは変更される場合があるため、申請前に必ず北九州市の公式サイトまたは窓口でご確認ください。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
