insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"fukuoka-kitakyushu-emergency-alert","status":"published","title":"あんしん通報システム（北九州市）","officialUrl":"https://www.city.kitakyushu.lg.jp/shoubou/14000050.html","topic":"emergency-alert"}'::jsonb, 'pilot:fukuoka-kitakyushu-emergency-alert:ZnVrdW9rYS1raXRha3l1c2h1LWVtZXJnZW5jeS1h' from public.support_programs sp where sp.slug='fukuoka-kitakyushu-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'fukuoka'), 'fukuoka-fukuoka-emergency-alert', '福岡市 緊急通報システム', '福岡市が実施する、ひとり暮らしの高齢者等を対象とした緊急通報装置の貸与事業です。急病や事故など緊急時に、ペンダント型ボタン等の操作で受信センターへ自動通報し、消防局や協力員への連絡につなげる見守り支援の可能性があります。詳細は公式サイトでご確認ください。', NULL, 'service', '市内に居住し、福岡市の介護保険被保険者である65歳以上のひとり暮らし高齢者、またはこれに準ずる方で、健康状態・身体状況に不安があり緊急時の連絡手段確保が困難な方が対象となる可能性があります。詳細な要件は公式サイトまたは各区保健福祉センターでご確認ください。', '貸与機器は固定電話型・携帯電話型の2種類。利用料（月額）は介護保険料段階に応じて異なり、第1〜3段階は無料、第4〜15段階は固定電話型948円・携帯電話型1,145円とされていますが、料金体系は変更される可能性があるため公式サイトでの確認をおすすめします。', '通年で随時受付とみられますが、公式サイトでの確認をおすすめします。', '各区保健福祉センター福祉・介護保険課の窓口または郵送、もしくはマイナポータルでのオンライン申請。原則として2名の緊急通報協力員の確保が必要とされています。', '申込書、調査書、協力員承諾書、契約書（2部）、介護保険被保険者証など。詳細は公式サイトまたは各区保健福祉センターでご確認ください。', TRUE, '福岡市 各区保健福祉センター福祉・介護保険課', NULL, 'https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020201.html', 'https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020201.html', '福岡市 緊急通報システム', '2026-07-01', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は公式サイトの内容に基づく概括であり、対象要件・料金・申込方法は個別の状況や区によって異なる場合があります。正確な最新情報は必ず公式サイトまたは各区保健福祉センター福祉・介護保険課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
