insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"fukuoka-fukuoka-emergency-alert","status":"published","title":"福岡市 緊急通報システム","officialUrl":"https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020201.html","topic":"emergency-alert"}'::jsonb, 'pilot:fukuoka-fukuoka-emergency-alert:ZnVrdW9rYS1mdWt1b2thLWVtZXJnZW5jeS1hbGVy' from public.support_programs sp where sp.slug='fukuoka-fukuoka-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html', 'WebFetchでofficialUrl(https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html)を検証。(a)到達可、(b)city.sapporo.jp配下で許可ホスト、(c)高齢者あんしんコール事業（緊急通報機器貸与・24時間相談対応）そのものの当該市ページであることを確認、(d)年度限定・受付終了の記載なし＝常時受付、(e)国/都道府県の一般制度ではなく札幌市独自事業、(f)対象者の複数区分（65歳以上ひとり暮らし等/60〜65歳要介護/85歳以上ひとり暮らし）が全体として記載されており一部を全体と誤認していない、(g)障害者向け「身体障がい者あんしんコール事業」との混同なし・高齢者版のみを対象、(h)断定的な「対象になります」等の表現はresearchNote/programとも回避され「〜対象となる可能性があります」「公式でご確認ください」という概括表現になっている。さらに、一次調査でuncertainFieldsとしていたbenefitAmountTextについて、実際は公式ページ（k160dokuji.' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hokkaido' and m.slug='sapporo' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/hitorigurashi/tsuho.html', 'WebFetchでofficialUrlを検証。(a)到達可、(b)city.sendai.jp配下で許可ホスト該当、(c)仙台市高齢企画課所管の緊急通報システム機器貸し出し事業そのものの当該市ページ、(d)最終更新2025年5月28日で現行、(e)国・都道府県制度の一般説明ではなく仙台市独自事業、(f)対象は「65歳以上ひとり暮らし等」で一次調査の記述と一致し部分を全体化していない、(g)重度身体障害者向けの別事業とは混同していない（今回programは高齢者向け1件のみ）。ページ内容: 対象=市内在住65歳以上の日常生活上注意を要するひとり暮らし高齢者、または実質ひとり暮らし状態の重度要介護者同居高齢者。費用=機器貸与・設置無料、月額利用料(警備員方式)550円税込、介護保険料第1・2段階は無料。申請=区役所・総合支所担当課または地域包括支援センター、事前に委託警備会社の訪問調査必要。必要書類=緊急通報システム端末利用申請書、利用確約書、(借家の場合)架設承諾書。なお「協力員方式」は平成27年1月末で新規受付終了となっているが、これは今回programが扱う警備員方式・機器貸与とは' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='miyagi' and m.slug='sendai' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.saitama.lg.jp/002/003/003/002/005/kinkyuutuuhou.html', 'WebFetchでofficialUrlに到達確認。city.saitama.lg.jp（許可ホスト）で、さいたま市独自の「ひとり暮らし高齢者等あんしんコールセンター相談事業（緊急通報機器の設置）」ページであることを確認。事業名・対象（65歳以上ひとり暮らし高齢者で慢性疾患等により常時注意を要する方）・費用負担（設置・維持管理費は市負担、利用者都合の再設置費や破損時実費は自己負担）・申請方法（区役所高齢介護課または電子申請）・問い合わせ先（福祉局長寿応援部高齢福祉課在宅事業係 048-829-1260）が一次調査の記載と完全一致。身体障害者を対象とする明記はなく、categorySlugsをnursing-careのみとした判断も妥当。国/都道府県事業の誤認、対象の一部を全体化、複数制度の混在、断定表現なし。uncertainFieldsも適切に設定されている。是正不要。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/kinkyuutuuhou.html', 'WebFetchで千葉市公式ページ本文を直接検証。(a)到達確認済み (b)city.chiba.jpは許可ホスト (c)千葉市独自の高齢者緊急通報システム事業そのものの当該市ページであることを確認 (d)ページ最終更新日2026年5月13日で最新。ただし「令和8年10月30日（金）をもって新規受付を終了」「新制度は令和9年1月開始予定」との記載を確認し、現行事業は見直し中で新制度へ移行予定であることが判明。これは事業が消滅するのではなく制度改定に伴う移行時期であるため、applicationDeadlineTextに正確に反映し、利用者には最新の受付状況を必ず公式・窓口で確認するよう明記した。(e)国・都道府県制度ではなく市独自事業 (f)対象の一部を全体と書いていない（ひとり暮らし高齢者+同居者要介護のケースを両方明記） (g)複数制度混在なし (h)費用・対象の細部は「〜場合があります」等の概括表現を維持し断定を避けた。program・prefectureSlug="chiba"・municipalitySlug="chiba"・slug="chiba-chiba-emergen' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/fukushi-kaigo/koreisha-kaigo/kaigohoken-igai-service/zaitaku-yoengo-shien/mimamori.html', 'WebFetchでofficialUrlを検証。到達可・ドメインcity.yokohama.lg.jp（許可ホスト）・ページタイトル「高齢者見守り・安否確認機器補助事業 横浜市」で当該市の緊急通報/見守り機器事業そのもの。対象者(65歳以上ひとり暮らし・他の見守りサービス非利用)、補助額(最大月額1,000円)、申請方法(利用者が登録事業者へ直接連絡・契約)、問い合わせ先(健康福祉局高齢在宅支援課 045-671-2405、メールkf-anpikakunin@city.yokohama.lg.jp)は一次調査の記載と完全一致。最終更新日2026年5月26日で「令和9年度の新規登録事業者募集は令和8年10月頃予定」との記載があり現行・受付中と確認（終了事業ではない）。旧「高齢者あんしん電話貸与事業」の後継として2025年度開始の現行事業であることも一次調査と整合。国/都道府県の一般制度ではなく横浜市独自事業であり、複数制度の混在や対象の部分を全体と誤記載する問題も見られない。categorySlugsをnursing-careのみとし重度障害者向け「あんしん電話」の扱いをuncertai' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='yokohama' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kawasaki.jp/350/page/0000022594.html', 'WebFetchでofficialUrl(https://www.city.kawasaki.jp/350/page/0000022594.html)を検証。(a)到達可能 (b)許可ホストcity.kawasaki.jpに一致 (c)川崎市健康福祉局長寿社会部高齢者在宅サービス課所管の「高齢者等緊急通報システム」の当該市ページであり、川崎市独自の緊急通報/見守り機器事業そのもの (d)更新日2026年4月1日で現行・受付終了の兆候なし (e)国/都道府県の一般制度ではなく川崎市独自事業 (f)携帯型・自宅設置型それぞれの対象要件が個別に明記されており、programのtargetPeopleは両方を概括した記述で一部を全体と誤認していない (g)重度身体障害者向け別事業(0000024337.html)とは明確に区別してprogramを高齢者向けのみに限定しており、disclaimerNoteでも言及済み・複数制度の混在なし (h)料金・対象の細目は「詳細は公式サイト・窓口でご確認ください」と非断定で概括。フェッチ結果（対象要件・料金0～4,580円・携帯型/自宅設置型の説明・申請窓' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='kawasaki' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006378.html', 'WebFetchでofficialUrlを検証。(a)到達確認OK (b)ホストはcity.sagamihara.kanagawa.jpで相模原市公式ドメイン、許可対象 (c)ページタイトル「緊急通報サービス」で相模原市独自の緊急通報事業（押しボタンで119番通報できる装置の貸与）の当該市ページであることを確認 (d)最終更新は令和5年5月2日で、受付終了等の記載なし・現行の事業として運用中 (e)ページ内容は市の独自事業として明記されており、国や県の一般的制度説明ではない (f)対象者は「65歳以上のひとり暮らし高齢者・高齢者のみ世帯」「常時注意が必要な高齢者」「重度身体障害者（ひとり暮らし・世帯のみ）」の3区分が明記されており、一次調査のtargetPeopleと整合、対象の一部を全体と誤記してもいない (g)単一制度で複数制度の混在は確認されず (h)disclaimerNote・uncertainFieldsに変更可能性・詳細要確認の断り書きが適切に含まれており、断定的な記述にはなっていない。categorySlugs/lifeEventSlugsにdisabilityを含めて' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='sagamihara' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.niigata.lg.jp/iryo/korei/anshinseikatsu/anshinrenraku.html', 'WebFetchでofficialUrlに到達し内容を確認。事業名「高齢者あんしん連絡システム」、実施主体は新潟市福祉部高齢者支援課、対象者要件（65歳以上のみ/65歳以上+重度障がい者の世帯かつ要介護状態等）、利用料（0円/550円/1,100円の月額課税段階制）、申請窓口（区役所健康福祉課高齢介護担当・地域保健福祉センター・地域包括支援センター）、必要書類（申請書・調査票1/2・利用確約書・協力員同意書）、装置内容（24時間受信センターへの通報装置貸与＋安否センサー＋月1回電話確認）のいずれも一次調査のprogram記載と整合。許可ホスト(city.niigata.lg.jp)・当該市独自事業・現行ページであることを確認し、FORBIDDEN表現や断定的記載も見当たらないため是正不要。program はそのまま採用。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='niigata' and m.slug='niigata' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.shizuoka.lg.jp/s2837/s002727.html', 'WebFetchでofficialUrl(city.shizuoka.lg.jp/s2837/s002727.html)を再取得し検証。(a)到達可 (b)静岡市公式許可ホスト一致 (c)当該市の緊急通報システム貸し出し事業そのもののページ (d)更新日2026年4月1日で現行年度、受付終了の兆候なし (e)静岡市独自事業として記載され国/都道府県制度の誤認なし (f)対象者(65歳以上ひとり暮らし/二人暮らし片方寝たきり、生活保護or市民税非課税、固定電話、緊急連絡先2件)は一次調査記載と完全一致、一部を全体化する誤りなし (g)複数制度の混在なし、単一事業 (h)非断定表現・「公式サイトで確認」の免責を維持。障害者対象の記載が無い点も再確認でき、categorySlugs=nursing-care/lifeEventSlugs=caregivingのみとした判断は妥当。申請方法について公式ページは「各区高齢介護課窓口または電子申請」とやや詳細だが、一次調査のapplicationMethodTextと矛盾はなく、政令市の区窓口対応という補足情報。是正の必要なし、foundのまま確定' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='shizuoka' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/kinkyuu.html', 'WebFetchでofficialUrlを検証。到達可能、ホストはcity.hamamatsu.shizuoka.jp（許可ホスト）で浜松市公式サイト。ページは浜松市独自の「緊急通報システムの貸与」事業そのもの（国・県制度の説明ではない）。対象者（65歳以上で循環器系疾患のあるひとり暮らし高齢者、75歳以上のひとり暮らし高齢者、75歳以上で支援が必要な高齢者世帯）、利用料（非課税世帯無料／課税世帯月額1,100円、通話料・通信テスト代は利用者負担）、「防犯目的ではなく、かけつけ業者は介護・医療行為を行わない」旨の注意書き、最終更新日2026年4月1日を再取得し、一次調査のresearchNote・program内容と完全に一致することを確認した。申込窓口の具体的手続きはページに明記されておらず高齢者相談センター等への相談案内にとどまる点も一致しており、この点は一次調査どおりuncertainFieldsに正しく計上済み。複数制度の混在や対象の一部を全体と書く誤りは見られない。断定的な保証表現もなくdisclaimerNoteも適切。是正の必要なし、一次調査のprogramをそのまま採用' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='hamamatsu' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.nagoya.jp/kenkofukushi/koureisha/1016427/1016428.html', '上記参照' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='aichi' and m.slug='nagoya' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kyoto.lg.jp/shobo/page/0000076672.html', 'officialUrl（city.kyoto.lg.jp、京都市公式・許可ホスト）をWebFetchで取得し到達確認。京都市消防局・保健福祉局所管の「緊急通報システム『あんしんネット119』」の当該市ページであり、市独自事業（国・都道府県制度の誤認なし）、複数制度の混在なし、更新日2025年4月14日で受付終了の記載なし＝現行と判断。さらに公式PDFリーフレット（https://www.city.kyoto.lg.jp/shobo/cmsfiles/contents/0000076/76672/anshinnet.pdf）をダウンロードしReadツールで全文読了し、一次調査のuncertainFieldsだった詳細をすべて裏付け確認：対象者は⑴おおむね65歳以上のひとり暮らし高齢者・高齢者のみ世帯等で心身病弱等のため緊急時自分で対処困難な方⑵ひとり暮らしの1・2級重度身体障害者や重度身体障害者のみ世帯等で同様の方⑶市長がこれらと同程度と認めたおおむね65歳以上の高齢者又は重度身体障害者の方。利用料（月額）は生計中心者の前年合計所得で4区分：A生活保護等受給世帯0円／B所得35万円以下1' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kyoto' and m.slug='kyoto' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.osaka.lg.jp/fukushi/page/0000006497.html', 'WebFetchでofficialUrlを実際に取得し検証した。(a)到達=OK、2026年7月1日更新の現行ページ。(b)ホスト=city.osaka.lg.jpで許可ホスト条件を満たす。(c)ページ内容は大阪市「緊急通報システム事業」そのもの（対象者・利用料・申請窓口・実施主体の記載あり）で、当該市固有のページと確認。(d)古い年度/受付終了の兆候なし。むしろ2026年5月1日付での利用料改定（858円→940円）が反映されており最新情報。一次調査のprogram.benefitAmountText（税込月額940円、非課税世帯無料）と一致。(e)国/都道府県の一般制度を市独自と誤認している様子はなく、大阪市福祉局高齢者施策部地域包括ケア推進課が実施主体として明記。(f)対象者の記載（65歳以上ひとり暮らし等／身体障がい2級以上等）は一次調査のtargetPeopleと整合し、一部を全体と偽っている様子はない。(g)複数制度の混在は見られず、緊急通報システム事業単体の説明。(h)FORBIDDEN表現・過度な断定は一次調査のprogram本文になく、disclaimerNoteで「' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='osaka' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kinkyutsuho.html', 'WebFetchでofficialUrlを検証。到達・許可ホスト(city.sakai.lg.jp)・当該市固有の高齢者緊急通報システム事業ページであることを確認。ページ内容: 対象は「ひとり暮らし高齢者または高齢者のみの世帯」「昼間・夜間独居となる病弱な高齢者」（具体的な年齢の明記はページ本文になし）。利用料金は生活保護世帯・所得税非課税世帯は無料、課税世帯は8,400円、独居対象者は機器代が別途実費という点は一次調査と一致。申込は区役所地域福祉課への書類提出、協力員2名の登録が必要（緊急通報受信時の状況確認等を行う）という点も一致。身体障害者を対象に含む記載はページ本文になし（「病弱等」表現のみ）ので、身体障害者緊急通報システムを別事業として扱った一次調査の判断は妥当。ページ更新日は2025年6月10日で現行性に問題なし。是正点は1つ：「おおむね65歳以上」という年齢基準はページ本文で直接確認できなかったため、targetPeopleの表現をやや慎重にし、uncertainFieldsに追加した。categorySlugs=nursing-caseのみとする判断、prefectur' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='sakai' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kobe.lg.jp/a10878/bosai/shobo/119/careline.html', 'WebFetchで公式ページ（city.kobe.lg.jp、許可ホスト該当）に到達し内容を確認。神戸市消防局が実施する「緊急通報システムケアライン119」で、対象は(1)ひとり暮らしで持病のある方、(2)重度身体障がい者、(3)65歳以上で病弱な方、およびこれらの方と同居し昼間ひとりで過ごす時間が長い方。固定電話（IP電話可・携帯電話不可）必須、近隣協力者の確保が要件。利用料金の記載なし、貸与機器の制度なし（短縮登録機能付き電話等の推奨のみ）、問い合わせ先は部署名のみで電話番号記載なし。申請は書面（近隣協力者・民生委員の署名）またはe-KOBE電子申請。最終更新2025-12-04で現行。国/県制度との混同なし、複数制度の混在なし、対象の一部を全体と誤記していない。神戸市独自の緊急通報事業ページとして適切であり、断定的な記載もない。一次調査のprogramは概ね正確で、uncertainFieldsとtargetPeopleを軽微に是正のうえfound/ok=trueとする。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.okayama.jp/kurashi/0000014403.html', 'WebFetchでofficialUrlを検証。(a)到達可能 (b)city.okayama.jp=許可ホスト（岡山市公式） (c)緊急通報システムの貸与・給付という当該事業そのものの市ページであることを確認 (d)ページ掲載日は2009年12月9日と古いが、受付終了・制度廃止の記載はなく、岡山市サイト内で現行案内として掲載されている（政令市の福祉サービスページは長期間更新されないことが多く、これのみでは「古い年度」と断定できない） (e)国・県制度の一般説明ではなく岡山市独自事業と明記 (f)対象者は複数区分（高齢者・重度身体障害者）が併記されており、一次調査のtargetPeopleはこれを概括的に反映、一部のみを全体化していない (g)緊急通報システム1事業のみを扱っており複数制度の混在なし (h)費用負担・対象要件は世帯状況により異なる旨を明記し断定を避けている。fetch結果は一次調査のprogram内容（対象者要件、費用負担の枠組み、申請方法、問い合わせ先）とほぼ完全に一致。prefectureSlug=okayama、municipalitySlug=okayama、s' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='okayama' and m.slug='okayama' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015440.html', 'WebFetchでofficialUrlを実機検証。(a)到達可（最終更新2025-03-18、受付終了等の記載なし＝現行）。(b)city.hiroshima.lg.jpで許可ホスト適合。(c)「あんしん電話設置（高齢者）」事業そのものの当該市ページで、機器貸与・月額利用料（課税¥1,683/非課税¥169/生保無料、固定・携帯で差あり）・区福祉課申請という一次調査の記載と完全一致。(d)古い年度/受付終了の兆候なし。(e)国/都道府県の一般制度説明ではなく市独自事業。(f)(g)対象混在・複数制度の混在なし。(h)ページは高齢者向けのみで障害者対象の明記が無いため、一次調査がcategorySlugs=nursing-careのみに絞りuncertainFieldsに明記した判断は妥当。金額・対象等はレンジ表記＋「公式で確認」の非断定表現を維持しており問題なし。program・prefectureSlug="hiroshima"・municipalitySlug="hiroshima"・slug="hiroshima-hiroshima-emergency-alert"はすべて一次' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kitakyushu.lg.jp/shoubou/14000050.html', 'WebFetchでofficialUrlを直接検証。(a)到達=OK。(b)許可ホスト=OK（city.kitakyushu.lg.jp、公式ドメイン、FAQ専用サブドメインではない）。(c)当該市の緊急通報/見守り事業そのもの=OK（「あんしん通報システム」北九州市独自事業、正式ページ）。(d)最新性=OK（更新日2025年9月24日、受付終了の記載なし）。(e)国/県制度の誤認=なし（北九州市独自の事業と明記、民間受託運営〔西部ガスリビング〕はあるが実施主体は市）。(f)対象の部分を全体化=なし（65歳以上高齢者のみ世帯、または重度身体障害者1・2級のみ世帯、または両者混在世帯、という一次調査の記載は公式内容と一致）。(g)複数制度の混在=なし（単一制度）。(h)断定表現=一次調査のtargetPeople/benefitAmountText/requiredDocumentsTextはいずれも「可能性があります」「とされています」「詳細は公式サイトで確認」等の非断定表現を使用しており適切。機器構成（緊急通報装置・煙センサー・熱センサー・ペンダント型送信機）もWebFetchの結果' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='kitakyushu' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020201.html', 'WebFetchでofficialUrlを検証。福岡市公式ドメイン(city.fukuoka.lg.jp、.lg.jp)に到達し、「緊急通報システム」という市独自の地域支援事業ページであることを確認。対象（65歳以上・介護保険被保険者・独居等で緊急時連絡手段確保が困難）、料金（介護保険料段階別、第1〜3段階無料、第4〜15段階は固定電話型948円/携帯電話型1145円）、機器（ペンダント型、固定電話型・携帯電話型の2種）、申込方法（各区保健福祉センター窓口・郵送・マイナポータル）、問い合わせ先（各区保健福祉センター福祉・介護保険課）が一次調査のprogram内容と完全に一致。最終更新日2025年2月6日で現行性も確認。国/県制度との混同、複数制度の混在、対象の一部を全体と誤認する記述もなし。program内の表現は「可能性があります」「公式サイトでご確認ください」等の非断定トーンを維持しており問題なし。是正不要、一次調査のprogramをそのまま最終とする。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='fukuoka' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.kumamoto.jp/list04390.html', '追加検証(2026-07-01)としてWebFetchでlist04390.htmlの内容を確認したが、緊急通報システム/緊急通報装置/見守り機器の貸与・設置支援に関する熊本市事業への言及・リンクは無し(掲載されているのは老人福祉センター、老人憩の家、シルバーヘルパー活動推進事業補助金、成年後見制度、認知症高齢者等見守りSOSネットワーク事業のみ)。WebSearchで「site:city.kumamoto.jp 緊急通報装置 貸与 高齢者」を実施したが、ヒットしたのは介護保険福祉用具貸与、障がい福祉課ページ、サ高住関連、認知症SOSネットワーク事業などで、緊急通報装置貸与に該当するページは見つからなかった。一次調査のresearchNoteの内容(民間警備会社サービスは市の事業ではない、SOSネットワーク事業は行方不明時発見のための別制度)とも整合しており、not_found_on_official_siteの判定を支持する。program は生成しない。今後の追加調査候補として、一次調査記載の介護保険課・高齢福祉課(096-328-2963)への電話確認や、高齢者福祉ガイドブックP' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kumamoto' and m.slug='kumamoto' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
